    for e in json.load(open(f)):
        preds[e['question_id']]=e['outcomes']
q=json.load(open('memory/questions.json'))
# active = not yet resolved; resolved ones from batch: 165622,227432,628026,892867,93950
resolved={'165622','227432','628026','892867','93950'}
soon=[x for x in q if x['rd']<='2026-01-20' and x['qid'] not in resolved]
soon.sort(key=lambda x:x['rd'])
for x in soon:
    p=preds.get(x['qid'])
    if p:
        top=max(p.values())
        items=', '.join(f'{k}:{v}' for k,v in sorted(p.items(),key=lambda kv:-kv[1])[:3])
        print(x['rd'],x['qid'],'top=%.2f'%top,'|',x['title'][:55],'|',items)
    else:
        print(x['rd'],x['qid'],'NOPRED','|',x['title'][:55])
